function mapPosition(lon: number, lat: number) {
  return { x: Number((((lon + 180) / 360) * 100).toFixed(1)), y: Number((((90 - lat) / 180) * 100).toFixed(1)) };
}

function makeFocusCountry(seed: FocusSeed): CountryProfile {
  const context = REGION_CONTEXT[seed.region];
  const localVocabulary = seed.localNames.join(', ');
  const connectedPlaces = seed.connections
    .slice(0, 3)
    .map((slug) => slug.split('-').map((word) => `${word.charAt(0).toUpperCase()}${word.slice(1)}`).join(' '))
    .join(', ');
  const sources = [
    ...seed.sourceKeys.map((key) => SHARED_SOURCES[key]),
    SHARED_SOURCES.globalHistory,
    SHARED_SOURCES.ethnopharmacology,
    SHARED_SOURCES.globalPrevalence,
    SHARED_SOURCES.unodcMarket,
  ].filter((source, index, list) => list.findIndex((item) => item.href === source.href) === index);

  return {
    slug: seed.slug,
    name: seed.name,
    code: seed.code,
    region: seed.region,
    accent: REGION_ACCENT[seed.region],
    mapPosition: mapPosition(seed.lon, seed.lat),
    localNames: seed.localNames,
    headline: seed.headline,
    deck: seed.deck,
    orientation: `${seed.deck} The longer regional history adds movement, material culture, language, medicine and power, but it does not imply that every community in ${seed.name} shared one practice. Read the country evidence first, then use the regional sections to understand the routes around it.`,
    editorialLens: `Keep ${seed.name} specific: distinguish regions, plant forms, time periods and the voices that produced each source. Regional context is a bridge for investigation, not a substitute for local evidence.`,
    policySummary: 'Current law is intentionally not summarized in this historical-focus profile until official primary sources receive a dedicated legal review.',
    policy: [],
    timeline: [
      ...seed.timeline.slice(0, 1).map(([date, title, body]) => ({ date, title, body })),
      { date: context.movementDate, title: context.movementTitle, body: `${context.movementBody} For ${seed.name}, this context should be tested against evidence from ${seed.places.join(' and ')}.` },
      { date: context.powerDate, title: context.powerTitle, body: `${context.powerBody} The exact sequence and institutions in ${seed.name} require country archives rather than a regional assumption.` },
      ...seed.timeline.slice(1).map(([date, title, body]) => ({ date, title, body })),
      { date: 'Across periods', title: 'Local vocabulary preserves different relationships', body: `Terms associated with this history include ${localVocabulary}. They may distinguish plant form, preparation, community, register or era; they should not be treated as perfect synonyms without local-language evidence.` },
      { date: 'Research now', title: 'Communities continue to revise the record', body: `Growers, patients, families, artists, healers, researchers and reform advocates hold evidence that formal archives may omit. A fuller history of ${seed.name} depends on their participation and consent.` },
    ],
    themes: [
      ...seed.themes.map(([eyebrow, title, body]) => ({ eyebrow, title, body })),
      { eyebrow: 'Language', title: 'Names are historical evidence', body: `${localVocabulary} appear in different contexts. Tracking who uses each term, for which preparation and in which period can reveal migration, stigma, expertise and cultural ownership.` },
      { eyebrow: 'Plant forms', title: 'Fibre, seed, flower and resin tell different stories', body: context.materialBody },
      { eyebrow: 'Routes', title: 'The country belongs to a connected map', body: `${seed.name} can be studied alongside ${connectedPlaces || 'neighboring and diasporic communities'}. Connections may involve ecology, trade, labor, religion, medicine, music, law or contemporary markets—not a claim that every route moved the same product.` },
      { eyebrow: 'Evidence', title: 'Official records are only one archive', body: context.archiveBody },
    ],
    places: [
      ...seed.places,
      `${seed.name} national, university and agricultural collections`,
      `Community, patient, grower and oral-history networks`,
    ],
    sources,
    connections: seed.connections,
    fieldQuestions: [
      `Which communities in ${seed.name} should review and extend this history?`,
      'Which local-language archives and oral histories are still missing?',
      'How did prohibition change who could preserve or publish plant knowledge?',
      `What do the terms ${localVocabulary} mean in their specific languages, places and generations?`,
      'Which claims concern fibre, seed, flower, resin, medicine, food or ritual—and which sources incorrectly merge them?',
      `How did movement between ${seed.name} and ${connectedPlaces || 'neighboring regions'} shape plant knowledge?`,
      'Where do government statistics describe enforcement rather than actual prevalence, benefit, cultivation or community meaning?',
      'What would ethical, locally governed research return to the people whose knowledge it records?',
    ],
    depth: 'focus',
  };
}

function makeBriefFocusCountry(seed: BriefFocusSeed): CountryProfile {
  const sourceKeys: FocusSeed['sourceKeys'] =
    seed.region === 'Africa' ? ['africa', 'global'] :
      seed.region === 'Europe' ? ['europe', 'global'] :
        seed.region === 'Oceania' ? ['oceania', 'global'] :
          seed.region === 'Asia' ? ['global', 'empire'] :
            ['americas', 'global'];

  return makeFocusCountry({
    slug: seed.slug,
    name: seed.name,
    code: seed.code,
    region: seed.region,
    lat: seed.lat,
    lon: seed.lon,
    localNames: seed.localNames,
    headline: seed.headline,
    deck: `${seed.history[2]} ${seed.modern[2]}`,
    timeline: [seed.history, seed.modern],
    themes: [
      ['Historical method', 'Separate evidence from inherited assumptions', seed.history[2]],
      ['Living history', 'Follow people as well as institutions', seed.modern[2]],
    ],
    places: seed.places,
    sourceKeys,
    connections: seed.connections,
  });
}

export const FOCUS_WORLD_COUNTRIES: CountryProfile[] = [
  ...focusSeeds.map(makeFocusCountry),
  ...briefFocusSeeds.map(makeBriefFocusCountry),
];
